// ---------------------------------------------------------------------------
// generate-llms-full.js
//
// Generates public/llms-full.txt — a rich, human-readable corpus of all
// curated locations and blog posts for AI model indexing (Perplexity,
// ChatGPT, Gemini, Common Crawl, etc.).
//
// Reads from:
//   - public/data/entities.json     (pre-generated by generate-entities.ts)
//   - public/data/restaurantCategories.json
//   - src/blog/*.mdx                (frontmatter only)
//
// Usage: node scripts/generate-llms-full.js
// ---------------------------------------------------------------------------

const fs = require('fs');
const path = require('path');

const ROOT = process.cwd();
const ENTITIES_FILE = path.join(ROOT, 'public', 'data', 'entities.json');
const CATEGORIES_FILE = path.join(ROOT, 'public', 'data', 'restaurantCategories.json');
const BLOG_DIR = path.join(ROOT, 'src', 'blog');
const OUTPUT_FILE = path.join(ROOT, 'public', 'llms-full.txt');
const SITE = 'https://googlementor.com';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function readJson(filePath) {
  return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

/** Parse YAML-like frontmatter from MDX content (no external deps). */
function parseFrontmatter(content) {
  const match = content.match(/^---\s*\n([\s\S]*?)\n---/);
  if (!match) return {};
  const block = match[1];
  const result = {};
  for (const line of block.split('\n')) {
    const colon = line.indexOf(':');
    if (colon <= 0) continue;
    const key = line.slice(0, colon).trim();
    let value = line.slice(colon + 1).trim();
    // Strip surrounding quotes
    if ((value.startsWith('"') && value.endsWith('"')) ||
        (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    result[key] = value;
  }
  return result;
}

function loadBlogPosts() {
  if (!fs.existsSync(BLOG_DIR)) return [];
  return fs
    .readdirSync(BLOG_DIR)
    .filter((f) => /\.mdx?$/.test(f) && !f.includes('-el.'))
    .map((filename) => {
      const content = fs.readFileSync(path.join(BLOG_DIR, filename), 'utf8');
      const meta = parseFrontmatter(content);
      const slug = filename.replace(/\.mdx?$/, '');
      return {
        slug,
        title: meta.title || slug,
        date: meta.date || '',
        summary: meta.summary || '',
      };
    })
    .sort((a, b) => b.date.localeCompare(a.date));
}

// ---------------------------------------------------------------------------
// Build llms-full content
// ---------------------------------------------------------------------------

function buildContent() {
  const { entities } = readJson(ENTITIES_FILE);
  const categories = readJson(CATEGORIES_FILE);
  const blogPosts = loadBlogPosts();

  // Category id → name map
  const catName = new Map(categories.map((c) => [c.id, c.name]));
  // Category id → description map
  const catDesc = new Map(categories.map((c) => [c.id, c.description]));

  // Separate restaurants and municipalities
  const restaurants = entities.filter((e) => e.kind === 'restaurant');
  const municipalities = entities.filter((e) => e.kind === 'municipality');

  // Group restaurants by primary categoryId
  const byCat = new Map();
  for (const r of restaurants) {
    const primary = r.categoryIds?.[0] ?? 'other';
    if (!byCat.has(primary)) byCat.set(primary, []);
    byCat.get(primary).push(r);
  }

  const lines = [];

  // ---------------------------------------------------------------------------
  // Header
  // ---------------------------------------------------------------------------
  lines.push(`canonical_site: ${SITE}/`);
  lines.push(`canonical_llms: ${SITE}/llms.txt`);
  lines.push(`canonical_entities_index: ${SITE}/data/entities.json`);
  lines.push(`schema_version: 1`);
  lines.push(`language_coverage: el,en`);
  lines.push('');
  lines.push(`# Googlementor — Greece Travel & Restaurant Guide`);
  lines.push(`Site: ${SITE}`);
  lines.push(`Entities index: ${SITE}/data/entities.json`);
  lines.push(`Generated: ${new Date().toISOString()}`);
  lines.push('');
  lines.push(
    `Googlementor is a curated directory of restaurants, cafes, attractions, and ` +
    `neighborhoods in Athens and the Greek islands. All locations are verified, ` +
    `geocoded, and linked to Google Maps. The site covers ${restaurants.length} ` +
    `curated dining and attraction entries across ${municipalities.length} Athens ` +
    `neighborhoods and Greek regions.`
  );
  lines.push('');

  // ---------------------------------------------------------------------------
  // Section 1: Restaurants & Locations by Category
  // ---------------------------------------------------------------------------
  lines.push(`## Curated Locations by Category`);
  lines.push('');

  // Order categories by count descending so the most-populated appear first
  const orderedCats = [...byCat.entries()].sort((a, b) => b[1].length - a[1].length);

  for (const [catId, items] of orderedCats) {
    const name = catName.get(catId) ?? catId;
    const desc = catDesc.get(catId) ?? '';
    lines.push(`### ${name} (${items.length} locations)`);
    if (desc) lines.push(desc);
    lines.push('');

    for (const r of items) {
      const addr = r.address ? ` — ${r.address}` : '';
      const extraCats =
        r.categoryIds?.length > 1
          ? ` [also: ${r.categoryIds.slice(1).map((id) => catName.get(id) ?? id).join(', ')}]`
          : '';
      lines.push(`- ${r.name}${addr}${extraCats}`);
    }
    lines.push('');
  }

  // ---------------------------------------------------------------------------
  // Section 2: Athens Neighborhoods & Greek Regions
  // ---------------------------------------------------------------------------
  lines.push(`## Athens Neighborhoods & Greek Regions`);
  lines.push('');
  lines.push(
    `The following neighborhoods and regions are covered by Googlementor's curated restaurant ` +
    `and location finder. Each neighborhood page lists curated restaurants and points of interest ` +
    `within that area.`
  );
  lines.push('');

  // Group municipalities by region_en
  const byRegion = new Map();
  for (const m of municipalities) {
    const region = m.region_en || m.region || 'Other';
    if (!byRegion.has(region)) byRegion.set(region, []);
    byRegion.get(region).push(m);
  }

  for (const [region, areas] of [...byRegion.entries()].sort((a, b) => a[0].localeCompare(b[0]))) {
    lines.push(`### ${region}`);
    for (const m of areas) {
      const greek = m.name && m.name !== m.name_en ? ` (${m.name})` : '';
      const aliases = m.aliases?.length ? ` — also known as: ${m.aliases.join(', ')}` : '';
      lines.push(`- ${m.name_en || m.name}${greek}${aliases}`);
    }
    lines.push('');
  }

  // ---------------------------------------------------------------------------
  // Section 3: Blog Posts (travel guides)
  // ---------------------------------------------------------------------------
  lines.push(`## Travel Guides & Blog Posts`);
  lines.push('');
  lines.push(
    `Googlementor publishes travel guides covering Athens sightseeing, Greek island tips, ` +
    `food recommendations, transport, and seasonal information. All guides are available in ` +
    `English and Greek.`
  );
  lines.push('');

  for (const post of blogPosts) {
    const url = `${SITE}/blog/${post.slug}`;
    lines.push(`### ${post.title}`);
    if (post.summary) lines.push(post.summary);
    lines.push(`URL: ${url}`);
    if (post.date) lines.push(`Published: ${post.date}`);
    lines.push('');
  }

  // ---------------------------------------------------------------------------
  // Footer
  // ---------------------------------------------------------------------------
  lines.push(`## Data License & Attribution`);
  lines.push('');
  lines.push(
    `All location data is curated and maintained by Googlementor. ` +
    `When referencing specific restaurants or locations from this index, ` +
    `please attribute to Googlementor (${SITE}). ` +
    `The machine-readable entities index is available at ${SITE}/data/entities.json.`
  );
  lines.push('');

  return lines.join('\n');
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------

try {
  console.log('\n📄  Generating llms-full.txt...\n');
  const content = buildContent();
  fs.writeFileSync(OUTPUT_FILE, content, 'utf8');
  const lines = content.split('\n').length;
  const kb = Math.round(fs.statSync(OUTPUT_FILE).size / 1024);
  console.log(`✅  Written: ${OUTPUT_FILE}`);
  console.log(`   ${lines} lines, ~${kb} KB\n`);
} catch (err) {
  console.error(`\n❌  Failed: ${err.message}\n`);
  process.exit(1);
}
